1	package golang
2	
3	import (
4		"fmt"
5		"strings"
6	
7		"github.com/sqlc-dev/sqlc/internal/codegen/golang/opts"
8		"github.com/sqlc-dev/sqlc/internal/metadata"
9		"github.com/sqlc-dev/sqlc/internal/plugin"
10	)
11	
12	type QueryValue struct {
13		Emit        bool
14		EmitPointer bool
15		Name        string
16		DBName      string // The name of the field in the database. Only set if Struct==nil.
17		Struct      *Struct
18		Typ         string
19		SQLDriver   opts.SQLDriver
20	
21		// Column is kept so late in the generation process around to differentiate
22		// between mysql slices and pg arrays
23		Column *plugin.Column
24	}
25	
26	func (v QueryValue) EmitStruct() bool {
27		return v.Emit
28	}
29	
30	func (v QueryValue) IsStruct() bool {
31		return v.Struct != nil
32	}
33	
34	func (v QueryValue) IsPointer() bool {
35		return v.EmitPointer && v.Struct != nil
36	}
37	
38	func (v QueryValue) isEmpty() bool {
39		return v.Typ == "" && v.Name == "" && v.Struct == nil
40	}
41	
42	type Argument struct {
43		Name string
44		Type string
45	}
46	
47	func (v QueryValue) Pair() string {
48		var out []string
49		for _, arg := range v.Pairs() {
50			out = append(out, arg.Name+" "+arg.Type)
51		}
52		return strings.Join(out, ",")
53	}
54	
55	// Return the argument name and type for query methods. Should only be used in
56	// the context of method arguments.
57	func (v QueryValue) Pairs() []Argument {
58		if v.isEmpty() {
59			return nil
60		}
61		if !v.EmitStruct() && v.IsStruct() {
62			var out []Argument
63			for _, f := range v.Struct.Fields {
64				out = append(out, Argument{
65					Name: escape(toLowerCase(f.Name)),
66					Type: f.Type,
67				})
68			}
69			return out
70		}
71		return []Argument{
72			{
73				Name: escape(v.Name),
74				Type: v.DefineType(),
75			},
76		}
77	}
78	
79	func (v QueryValue) SlicePair() string {
80		if v.isEmpty() {
81			return ""
82		}
83		return v.Name + " []" + v.DefineType()
84	}
85	
86	func (v QueryValue) Type() string {
87		if v.Typ != "" {
88			return v.Typ
89		}
90		if v.Struct != nil {
91			return v.Struct.Name
92		}
93		panic("no type for QueryValue: " + v.Name)
94	}
95	
96	func (v *QueryValue) DefineType() string {
97		t := v.Type()
98		if v.IsPointer() {
99			return "*" + t
100		}
101		return t
102	}
103	
104	func (v *QueryValue) ReturnName() string {
105		if v.IsPointer() {
106			return "&" + escape(v.Name)
107		}
108		return escape(v.Name)
109	}
110	
111	func (v QueryValue) UniqueFields() []Field {
112		seen := map[string]struct{}{}
113		fields := make([]Field, 0, len(v.Struct.Fields))
114	
115		for _, field := range v.Struct.Fields {
116			if _, found := seen[field.Name]; found {
117				continue
118			}
119			seen[field.Name] = struct{}{}
120			fields = append(fields, field)
121		}
122	
123		return fields
124	}
125	
126	func (v QueryValue) Params() string {
127		if v.isEmpty() {
128			return ""
129		}
130		var out []string
131		if v.Struct == nil {
132			if !v.Column.IsSqlcSlice && strings.HasPrefix(v.Typ, "[]") && v.Typ != "[]byte" && !v.SQLDriver.IsPGX() {
133				out = append(out, "pq.Array("+escape(v.Name)+")")
134			} else {
135				out = append(out, escape(v.Name))
136			}
