91			return v.Struct.Name
92		}
93		panic("no type for QueryValue: " + v.Name)
94	}
95	
96	func (v *QueryValue) DefineType() string {
97		t := v.Type()
98		if v.IsPointer() {
99			return "*" + t
100		}
101		return t
102	}
103	
104	func (v QueryValue) UniqueFields() []Field {
105		seen := map[string]struct{}{}
106		fields := make([]Field, 0, len(v.Struct.Fields))
107	
108		for _, field := range v.Struct.Fields {
109			if _, found := seen[field.Name]; found {
110				continue
111			}
112			seen[field.Name] = struct{}{}
113			fields = append(fields, field)
114		}
115	
116		return fields
117	}
118	
119	func (v QueryValue) Params() string {
120		if v.isEmpty() {
121			return ""
122		}
123		var out []string
124		if v.Struct == nil {
125			if !v.Column.IsSqlcSlice && strings.HasPrefix(v.Typ, "[]") && v.Typ != "[]byte" && !v.SQLDriver.IsPGX() {
126				out = append(out, "pq.Array("+escape(v.Name)+")")
127			} else {
128				out = append(out, escape(v.Name))
129			}
130		} else {
131			for _, f := range v.Struct.Fields {
132				if !f.HasSqlcSlice() && strings.HasPrefix(f.Type, "[]") && f.Type != "[]byte" && !v.SQLDriver.IsPGX() {
133					out = append(out, "pq.Array("+escape(v.VariableForField(f))+")")
134				} else {
135					out = append(out, escape(v.VariableForField(f)))
136				}
137			}
138		}
139		if len(out) <= 3 {
140			return strings.Join(out, ",")
141		}
142		out = append(out, "")
143		return "\n" + strings.Join(out, ",\n")
144	}
145	
146	func (v QueryValue) ColumnNames() []string {
147		if v.Struct == nil {
148			return []string{v.DBName}
149		}
150		names := make([]string, len(v.Struct.Fields))
151		for i, f := range v.Struct.Fields {
152			names[i] = f.DBName
153		}
154		return names
155	}
156	
157	func (v QueryValue) ColumnNamesAsGoSlice() string {
158		if v.Struct == nil {
159			return fmt.Sprintf("[]string{%q}", v.DBName)
160		}
161		escapedNames := make([]string, len(v.Struct.Fields))
162		for i, f := range v.Struct.Fields {
163			if f.Column != nil && f.Column.OriginalName != "" {
164				escapedNames[i] = fmt.Sprintf("%q", f.Column.OriginalName)
165			} else {
166				escapedNames[i] = fmt.Sprintf("%q", f.DBName)
167			}
168		}
169		return "[]string{" + strings.Join(escapedNames, ", ") + "}"
170	}
171	
172	// When true, we have to build the arguments to q.db.QueryContext in addition to
173	// munging the SQL
174	func (v QueryValue) HasSqlcSlices() bool {
175		if v.Struct == nil {
176			return v.Column != nil && v.Column.IsSqlcSlice
177		}
178		for _, v := range v.Struct.Fields {
179			if v.Column.IsSqlcSlice {
180				return true
181			}
182		}
183		return false
184	}
185	
